((SELECT id FROM public.games WHERE name='Caribbean Stud Poker'),'payout','Player wins with Four of a Kind (pays 20:1 on the Bet). Calculate the full 20:1 payout before applying the $1,000 table cap.',NULL,'20','Four of a Kind pays 20 to 1 on the Bet; in live play the total payout is capped at the $1,000 table maximum.','csp_bet',FALSE,3,10,TRUE),
