((SELECT id FROM public.games WHERE name='Caribbean Stud Poker'),'payout','The player''s quads beat the dealer. Calculate the 20:1 Bet payout (payouts are capped at $1,000 in live play).',NULL,'20','Four of a Kind pays 20 to 1 on the Bet, capped at the table maximum.','csp_bet',FALSE,3,10,TRUE),
((SELECT id FROM public.games WHERE name='Caribbean Stud Poker'),'payout','Player wins with a Straight Flush (pays 50:1 on the Bet). Calculate the full 50:1 payout before the $1,000 cap.',NULL,'50','A Straight Flush pays 50 to 1 on the Bet; the cards must also be sent to Surveillance.','csp_bet',FALSE,3,10,TRUE),
