((SELECT id FROM public.games WHERE name='Caribbean Stud Poker'),'payout','A Straight Flush beats the dealer''s hand. Calculate the 50:1 Bet payout (capped at $1,000 in live play).',NULL,'50','A Straight Flush pays 50 to 1 on the Bet.','csp_bet',FALSE,3,10,TRUE),
