INSERT INTO public.questions (game_id,type,question_text,options,correct_answer,explanation,category,is_procedure,difficulty,points,is_active)
VALUES
(NULL,'multiple_choice','What minimum hand must the dealer have to qualify (open) in Caribbean Stud Poker?','["At least Ace/King or higher","At least one Pair","Any Ace","Queen high or better"]','At least Ace/King or higher','The dealer must have a hand of at least an Ace/King or higher to qualify; otherwise the dealer calls ''no hand''.','caribbean_stud_procedure',TRUE,1,10,TRUE),
(NULL,'multiple_choice','How are the cards dealt in Caribbean Stud Poker?','["Five cards face down to each player and the dealer, with the dealer''s last card turned face up","Five cards face up to everyone","Two cards down and three up, like stud","Seven cards to each player"]','Five cards face down to each player and the dealer, with the dealer''s last card turned face up','The Dealer deals five cards to each player and to him/herself face down, except the Dealer''s last card, which is turned face up.','caribbean_stud_procedure',TRUE,1,10,TRUE),
(NULL,'multiple_choice','How does a player join the progressive jackpot?','["By placing $1 on the red circle above the Ante before the lock-out","By doubling their Ante","By telling the dealer verbally","By placing $5 in the betting circle"]','By placing $1 on the red circle above the Ante before the lock-out','A player wishing to participate in the progressive wagers $1 on the red circle above the Ante; the red light confirms the bet.','caribbean_stud_procedure',TRUE,1,10,TRUE),
(NULL,'multiple_choice','How much must a player wager to ''call'' the dealer''s hand?','["Exactly twice the amount of their Ante","The same amount as their Ante","Any amount up to the table maximum","Half of their Ante"]','Exactly twice the amount of their Ante','To call and stay in the game, the player must make an additional bet of exactly twice the amount of the Ante.','caribbean_stud_procedure',TRUE,1,10,TRUE),
(NULL,'multiple_choice','The dealer does not qualify. What is paid to players who called?','["Even money on the Ante only — the Bet is a push","Both the Ante and the Bet at even money","Nothing — all bets push","The Bet only"]','Even money on the Ante only — the Bet is a push','If the dealer''s hand does not contain at least Ace/King, the dealer calls ''no hand'' and pays even money on the Ante only.','caribbean_stud_procedure',TRUE,1,10,TRUE),
(NULL,'multiple_choice','Player and dealer hold completely identical hands. What happens?','["It is a push — no action on the hand","The player wins automatically","The dealer wins automatically","The Ante is paid but the Bet loses"]','It is a push — no action on the hand','A tie hand between player and dealer constitutes no action and is a push; only a higher 3rd, 4th or 5th card breaks a tie.','caribbean_stud_procedure',TRUE,1,10,TRUE),
(NULL,'multiple_choice','Does cash (currency) ever play as a bet in Caribbean Stud Poker?','["No — money does not play under any circumstances","Yes, if under $100","Yes, with Manager approval","Only on the progressive"]','No — money does not play under any circumstances','The procedures state plainly that money (cash) does not play under any circumstances.','caribbean_stud_procedure',TRUE,1,10,TRUE),
(NULL,'multiple_choice','Which button does the dealer press before dealing to stop further progressive bets?','["The lock-out button","The reset button","The green shuffle button","The payout key"]','The lock-out button','Before dealing, the dealer presses the lock-out button to restrict further betting on the progressive jackpot.','caribbean_stud_procedure',TRUE,1,10,TRUE),
(NULL,'multiple_choice','Which button does the dealer press after each hand so players can bet the progressive again?','["The reset button","The lock-out button","The payoff key","The service button"]','The reset button','At the completion of each hand the dealer presses the reset button, allowing players to bet on the progressive jackpot again.','caribbean_stud_procedure',TRUE,1,10,TRUE),
(NULL,'multiple_choice','What may the dealer never do with currency or chips?','["Give them to or take them from a player''s hand","Count them on the layout","Spread them for surveillance","Announce the amount out loud"]','Give them to or take them from a player''s hand','Never give or take currency or chips from a player''s hand — all transactions are completed on the layout in public view.','caribbean_stud_procedure',TRUE,1,10,TRUE);
INSERT INTO public.questions (game_id,type,question_text,options,correct_answer,explanation,category,is_procedure,difficulty,points,is_active)
VALUES
(NULL,'multiple_choice','When must a Caribbean Stud dealer call out ''checks play''?','["When dealing to any bet of $100 or more","On every winning bet","Only on progressive wins","When a player buys in with cash"]','When dealing to any bet of $100 or more','When dealing to any bet of $100 or more, the Dealer must call ''checks play'' so the table manager is aware of the action.','caribbean_stud_procedure',TRUE,2,10,TRUE),
(NULL,'multiple_choice','A player makes a Straight Flush or Royal Flush. What happens to the cards?','["The decks are delivered to Surveillance","They are shuffled back in and play continues","They are framed for display","They are dropped in the drop box"]','The decks are delivered to Surveillance','With any Straight Flush and up, the cards must be sent to Surveillance.','caribbean_stud_procedure',TRUE,2,10,TRUE),
(NULL,'multiple_choice','A player shows Four of a Kind or better with a progressive bet. What must happen before the payout?','["Surveillance is called to verify the hand and the Manager approves the payout","The dealer pays immediately to keep the game moving","The player signs a receipt","The cards are reshuffled first"]','Surveillance is called to verify the hand and the Manager approves the payout','For 4 of a Kind and up, Surveillance must verify that everything is correct and the Manager must approve before the payout is made; new decks are then placed in the game.','caribbean_stud_procedure',TRUE,2,10,TRUE),
(NULL,'multiple_choice','When does Surveillance receive all cards from a table?','["When the table has a significant win or loss greater than $10,000 in a shift","At the end of every shift","Whenever a deck is a month old","Only when a player complains"]','When the table has a significant win or loss greater than $10,000 in a shift','Surveillance receives all cards from any table that incurs a significant win or loss of greater than $10,000 in any shift.','caribbean_stud_procedure',TRUE,2,10,TRUE),
(NULL,'multiple_choice','How must the dealer place the cards for spots 1 and 2?','["With the left hand only","With the right hand only","With both hands together","By sliding them across the layout"]','With the left hand only','The Dealer places the cards for spot number 1 and 2 with the left hand only.','caribbean_stud_procedure',TRUE,2,10,TRUE),
(NULL,'multiple_choice','A player folds. What does the dealer do?','["Collect the Ante and the cards, spread and count them, then place them in the discard rack","Return the Ante and take the cards","Leave the cards until the hand is over","Collect the Ante and leave the cards face down"]','Collect the Ante and the cards, spread and count them, then place them in the discard rack','When a player folds, the dealer collects the cards and the Ante, spreads and counts the cards, then places them into the discard rack.','caribbean_stud_procedure',TRUE,2,10,TRUE),
(NULL,'multiple_choice','Two of the dealer''s cards are exposed during the deal. What is the ruling?','["It is a misdeal","The game continues normally","Only the dealer''s hand is void","The exposed cards become the face-up cards"]','It is a misdeal','An exposed player card does not constitute a misdeal, but if two of the dealer''s cards are exposed it is a misdeal.','caribbean_stud_procedure',TRUE,2,10,TRUE),
(NULL,'multiple_choice','A player is dealt an incorrect number of cards. What is the ruling?','["All hands are void and the cards are reshuffled","Only that player''s hand is void","The dealer deals replacement cards","The player plays the cards dealt"]','All hands are void and the cards are reshuffled','If any player or the dealer is dealt an incorrect number of cards, all hands shall be voided and the cards reshuffled.','caribbean_stud_procedure',TRUE,2,10,TRUE),
(NULL,'multiple_choice','In what order does the dealer compare, pay and take hands?','["From right to left","From left to right","Highest bet first","Progressive players first"]','From right to left','The dealer compares, pays and takes from right to left.','caribbean_stud_procedure',TRUE,2,10,TRUE),
(NULL,'multiple_choice','May the dealer total the Bet and the Ante into a single payout?','["No — pay the Ante by sizing into the bet; do not total them","Yes, to speed up the game","Yes, but only under $100","Only when the Manager is watching"]','No — pay the Ante by sizing into the bet; do not total them','General rules: pay the Ante by sizing into the bet for speed and accuracy, and do not total the Bet and Ante.','caribbean_stud_procedure',TRUE,2,10,TRUE);
INSERT INTO public.questions (game_id,type,question_text,options,correct_answer,explanation,category,is_procedure,difficulty,points,is_active)
VALUES
(NULL,'multiple_choice','Under the progressive jackpot schedule, what does a Straight pay?','["$25","$50","$100","$500"]','$25','Progressive payoffs: Royal Flush 100%, Straight Flush 10%, Four of a Kind $500, Full House $100, Flush $50, Straight $25.','caribbean_stud_procedure',TRUE,3,10,TRUE),
(NULL,'multiple_choice','Two or more players qualify for the progressive jackpot on the same hand. Who is paid first?','["The lowest-value hand first, progressing to the highest","The highest-value hand first","The player closest to the dealer","They are paid simultaneously"]','The lowest-value hand first, progressing to the highest','When multiple players qualify on the same deal, pay the lowest value hands first, progressing to the highest, reducing the progressive amount after each payout.','caribbean_stud_procedure',TRUE,3,10,TRUE),
(NULL,'multiple_choice','Two players make a Royal Flush on the same deal. How is the 100% jackpot handled?','["The winners share the jackpot as an aggregate","The first player dealt takes it all","Each is paid 100% of the jackpot","The jackpot rolls over to the next hand"]','The winners share the jackpot as an aggregate','If two or more players qualify for all or part of the progressive jackpot during the same hand, the winners share the jackpot as an aggregate.','caribbean_stud_procedure',TRUE,3,10,TRUE),
(NULL,'multiple_choice','The dealer does not qualify, but a player holds a progressive-qualifying hand. What is paid?','["The Ante and the progressive — NOT the Bet to call the dealer","Nothing until the next qualifying hand","The Bet and the progressive","Only the progressive"]','The Ante and the progressive — NOT the Bet to call the dealer','If the dealer does not have a qualifying hand, players with progressive-qualifying hands are paid the Ante and the progressive, but not the Bet.','caribbean_stud_procedure',TRUE,3,10,TRUE),
(NULL,'multiple_choice','What are the Caribbean Stud wagering limits?','["Ante up to $250, Bet up to $500, all payouts capped at the $1,000 table limit","Ante up to $500, Bet up to $1,000, no payout cap","Ante and Bet both up to $1,000","Ante up to $100, Bet up to $200, payouts capped at $500"]','Ante up to $250, Bet up to $500, all payouts capped at the $1,000 table limit','The limit on the Ante is up to $250, the limit on the Bet is $500, and all payouts are up to the $1,000 table limit.','caribbean_stud_procedure',TRUE,3,10,TRUE),
(NULL,'multiple_choice','Which chips may go into the toke box without a Manager''s color change?','["Only checks of $25 or less","Any denomination","Checks up to $100","Only $1 and $5 checks"]','Only checks of $25 or less','No checks over $25 will be placed in the toke box; a Manager authorizes any necessary color change first.','caribbean_stud_procedure',TRUE,3,10,TRUE),
(NULL,'multiple_choice','At closing, who is allowed to drop the Closer slip?','["Only the dealer, unless two table Managers conduct the count","Any Manager","The Security Officer","The cashier"]','Only the dealer, unless two table Managers conduct the count','Only the dealer is allowed to drop the Closer slip, unless two table Managers conduct the count.','caribbean_stud_procedure',TRUE,3,10,TRUE),
(NULL,'multiple_choice','Which denominations are run down in stacks no greater than four high?','["$2.50, $25, $500 and $5,000 cheques","$1, $5, $100 and $1,000 cheques","All denominations","Only $500 and above"]','$2.50, $25, $500 and $5,000 cheques','$2.50, $25, $500 and $5,000 cheques are cut four high; $1, $5, $100 and $1,000 cheques are cut five high — never more than 20 in a row.','caribbean_stud_procedure',TRUE,3,10,TRUE),
(NULL,'multiple_choice','What must the dealer verify on a Marker before signing?','["Player''s name, game type, table number and amount — then sign with kronus number","Only the total amount","Only the player''s name and date","Nothing — the Manager verifies everything"]','Player''s name, game type, table number and amount — then sign with kronus number','The dealer must verify all information on the Marker (player''s name, game type, table number, amount) and sign with their kronus number.','caribbean_stud_procedure',TRUE,3,10,TRUE),
(NULL,'multiple_choice','A player who did NOT bet the progressive makes a Flush. How is the hand paid?','["Call a Manager and pay normal table odds with approval — not the progressive","Pay the progressive anyway as a courtesy","Pay nothing beyond the Ante","Let the player choose table odds or progressive"]','Call a Manager and pay normal table odds with approval — not the progressive','If the player is not participating in the progressive and makes a qualifying hand, a Manager is called and the payout is made at normal table odds, not the progressive odds.','caribbean_stud_procedure',TRUE,3,10,TRUE);
